CREATE TRIGGER SubscriptionsSetCourseRatingOnUpdate
    AFTER UPDATE ON Subscription
    FOR EACH ROW
BEGIN
    -- Verifica se il valore di 'Vote' è cambiato
    IF NEW.Vote <> OLD.Vote THEN
        UPDATE Courses
        SET Rating = (
            SELECT AVG(Vote)
            FROM Subscription
            WHERE CourseId = NEW.CourseId
        )
        WHERE Id = NEW.CourseId;
    END IF;
END;








